var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，得到回應說他馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"참 우습지 않나.","JPN":"まったく、笑えないな。","ENG":"How funny is it?","TWN":"難道不可笑嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"전쟁이 끝난 지 그렇게 오래되지도 않았는데, 사람들은 벌써 모든 문제가 해결된 것처럼 지내고 있어.","JPN":"戦争が終わったばかりなのに、人々はもうすべての問題が解決されたと思い込んで過ごしている。","ENG":"It hasn't been long since the war ended, and people are already acting like all the problems have been solved.","TWN":"戰爭還沒結束多久，人們就好像所有問題都被解決了一樣，繼續過著日子。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"전선에 발 한 번 붙여 본 적 없는 정치가들은 우리가 평화를 되찾았다고 떠들어대지만......","JPN":"戦場に立ったことのない政治家たちは、私たちが平和を取り戻したとはやし立てるが……","ENG":"Politicians, who's never set foot on the battlefield, proudly boast that we've regained peace,","TWN":"雖然那些從未上過前線的政治家，嚷嚷著我們已經取回了和平……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"평화는 아직 오지 않았다. 지금은 다들 겁에 질려 현실을 외면하고 있을 뿐이야.","JPN":"平和はまだ訪れていない。今は皆、怖くて現実から目をそらしているだけだ。","ENG":"but peace never came back. Everyone's just too scared to acknowledge the truth.","TWN":"但和平還沒有到來，大家現在只是在無視恐怖的現實罷了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"전쟁을 치르면서 이면세계에 대해 많은 걸 알게 되었지.","JPN":"戦の最中に、カウンターサイドについていろんなことがわかったんだ。","ENG":"Through the war, I've learned a lot about the Counterside.","TWN":"通過戰爭，我對異界有了許多了解。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"우리가 극적으로 승리했던 대정화 전쟁도, 저들에게는 가벼운 장난에 불과해.","JPN":"私たちが劇的に勝利した大浄化戦争も、彼らにとってはただの遊びにすぎない。","ENG":"The Grand Purification War, which we fought so hard to attain victory, was nothing but a joke to them.","TWN":"我們獲得戲劇性勝利的大淨化戰爭，對他們來說，不過是個小玩笑罷了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 껍데기뿐인 평화에 취한 자들은 아무리 경고해도 들으려 하지 않더군.","JPN":"しかし、偽りの平和に甘んずる者たちは、いくら警告しても耳を傾けようともしない。","ENG":"But no matter how I tried to warn them, they wouldn't listen.","TWN":"然而，不管再怎麼警告那些沉醉在表面和平的人們，他們連聽都不想聽。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"결국...... 누군가 나서는 수밖에 없어.","JPN":"結局……誰かが前に出るしかない。","ENG":"In the end, someone's got to step up.","TWN":"結果……就必須得有人站出來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이해해 주길 바라지는 않겠다. 자네에게도 자네만의 방식이 있을 테니까.","JPN":"理解してほしいとは言わない。君にも君のやり方があるはずだ。","ENG":"I don't expect you to understand me. And I'm sure you have your own ideas","TWN":"我不指望你會理解我。畢竟你也有你自己的方式。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......우리에게 정해진 결말을 피하는 방법 말이지.","JPN":"……私たちが、決まった結末を避ける方法がな。","ENG":"as to how we could avoid the doom reserved for us.","TWN":"……關於要怎麼迴避既定結局的方法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};